import classes from "./LoginInput.module.css";

const LoginInput = (props) => {
  return (
    <div className={classes['wrapper']}>
      {props.label && <label>{props.label}</label>}
      <input id={props.id} type={props.type}></input>
    </div>
  );
};
export default LoginInput;
